//! Spec-compliance tests: Table Style Cascade & Conditional Formatting (ISO 29500-1 §17.7.6)
//!
//! These tests verify table style resolution edge cases against the OOXML spec:
//! - Conditional formatting precedence (§17.7.6)
//! - Table style paragraph properties (§17.7.6.1)
//! - Table style run properties (§17.7.6.2)
//! - Cell margin inheritance chain (§17.4.43)
//! - Band row/column interaction
//! - Table-level style properties (alignment, indent)
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/table-cascade";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &stemma::TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t),
            _ => None,
        })
        .expect("document should contain at least one table")
}

/// Get the first paragraph in a table cell.
fn cell_first_paragraph(
    table: &stemma::TableNode,
    row: usize,
    col: usize,
) -> &stemma::ParagraphNode {
    let cell = &table.rows[row].cells[col];
    cell.blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("cell should contain at least one paragraph")
}

/// Get the first text node in a table cell.
fn cell_first_text_node(table: &stemma::TableNode, row: usize, col: usize) -> &stemma::TextNode {
    let cell = &table.rows[row].cells[col];
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    return t;
                }
            }
        }
    }
    panic!("cell ({row},{col}) should contain at least one text node")
}

// ── Conditional formatting precedence (§17.7.6) ────────────────

/// MS-OI29500 §17.7.6(c): Conditional format precedence at corner cell (0,0).
///
/// Per MS spec, the precedence order is (higher overrides lower):
///   wholeTable < bands < firstCol/lastCol < firstRow/lastRow < corners
///
/// Cell (0,0) matches both firstRow (blue 4472C4) and firstCol (green 70AD47).
/// Per MS behavior, firstRow has HIGHER precedence than firstCol: blue (4472C4).
///
/// Note: The base ISO spec says firstCol > firstRow, but MS Word does the opposite.
/// Precedence corrected to match MS behavior.
#[test]
fn spec_conditional_precedence_corner_top_left() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    // Cell (0,0): firstRow AND firstCol both match.
    // Per MS-OI29500 §17.7.6: firstRow > firstCol → blue (4472C4).
    let shading = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("corner cell (0,0) should have shading");
    assert_eq!(
        shading.fill.as_deref(),
        Some("4472C4"),
        "cell (0,0): firstRow (blue) should override firstCol (green) per MS-OI29500 §17.7.6"
    );
}

/// MS-OI29500 §17.7.6(c): Top-right corner: firstRow > lastCol.
///
/// Cell (0,2): firstRow (blue 4472C4) AND lastCol (red FF0000).
/// Per MS behavior, firstRow has HIGHER precedence: blue (4472C4).
#[test]
fn spec_conditional_precedence_corner_top_right() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence");
    let table = first_table(&doc);

    let shading = table.rows[0].cells[2]
        .formatting
        .shading
        .as_ref()
        .expect("corner cell (0,2) should have shading");
    assert_eq!(
        shading.fill.as_deref(),
        Some("4472C4"),
        "cell (0,2): firstRow (blue) should override lastCol (red) per MS-OI29500 §17.7.6"
    );
}

